const b = $json.body || $json;
const jobId = b.jobId || '';
const chatId = String((b.telegram && b.telegram.chatId) || '');
const plan = (b.parsedOutput && b.parsedOutput.result) || b.result || '';
// Only render when the plan is actually ready. Ignore the runner's job-start callback
// (event:'started' / status:'running') which carries no plan yet — it was producing a
// premature '(planner returned no plan text)' card with live buttons.
if (!chatId || !jobId || b.event === 'started' || b.status === 'running' || !plan.trim()) { return []; }
const out = [];
const MAX = 3800;
const body = plan.trim();
for (let i = 0; i < body.length; i += MAX) { out.push({ json: { chatId, text: body.slice(i, i + MAX) } }); }
const kb = JSON.stringify({ inline_keyboard: [[
  { text: '\u2705 Approve & Implement', callback_data: 'plan:approve:' + jobId },
  { text: '\u274c Reject', callback_data: 'plan:reject:' + jobId }
]] });
out.push({ json: { chatId, text: '\ud83d\udccb Plan ready (job ' + jobId + '). Approve to dispatch engineer-implementer, or reject.', keyboard: kb } });
return out;
